// src/pages/Dashboard/Dashboard.jsx

import React from 'react';
import { Link } from 'react-router-dom';

const Dashboard = ({ role }) => {
  // Gambar profil berdasarkan role, bisa kamu ganti sesuai kebutuhan
  const profileImages = {
    Admin: '/images/admin.png',         // contoh gambar lokal di public/images/admin.png
    'Super Admin': '/images/superadmin.png', // contoh gambar lokal di public/images/superadmin.png
  };

  const userImage = profileImages[role] || '/images/default-user.png';

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar */}
      <div className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img
              src={userImage}
              alt={`${role} Icon`}
              className="rounded-full mb-2 w-16 h-16 object-cover"
            />
            <h2 className="font-semibold text-lg">{role}</h2>
          </div>

          <div className="space-y-6">
            {role === 'Admin' && (
              <div className="bg-gray-700 rounded-lg p-3 text-center">
                <Link to="/master-data" className="block hover:text-white">Master Data</Link>
              </div>
            )}
            <div className="bg-gray-700 rounded-lg p-3 text-center">
              <Link to="/tracking" className="block hover:text-white">Tracking</Link>
            </div>
            <div className="bg-gray-700 rounded-lg p-3 text-center">
              <Link to="/info-driver" className="block hover:text-white">Info Driver</Link>
            </div>
            {role === 'Super Admin' && (
              <div className="bg-gray-700 rounded-lg p-3 text-center">
                <Link to="/bypass" className="block hover:text-white">By Pass</Link>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-6 mt-6">
          <div className="bg-gray-700 rounded-lg p-3 text-center">
            <Link to="/settings" className="block hover:text-white">Settings</Link>
          </div>
          <div className="bg-gray-700 rounded-lg p-3 text-center">
            <Link to="/logout" className="block hover:text-white">Logout</Link>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-6">
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-bold">Dashboard</h1>

          <div className="flex items-center space-x-4">
            <input
              type="text"
              placeholder="Search..."
              className="px-4 py-2 border rounded-lg"
            />
            <img
              src="/images/notification-icon.png"  // Ganti dengan gambar notifikasi kamu
              alt="Notification Icon"
              className="w-6 h-6 cursor-pointer"
            />
            <img
              src={userImage}
              alt="User Icon"
              className="w-8 h-8 rounded-full cursor-pointer object-cover"
            />
          </div>
        </div>

        {/* Konten utama dapat ditambahkan di sini */}
      </div>
    </div>
  );
};

export default Dashboard;
